export function getInitialImageData(data) {
  const NUMBER_OF_FEED_IN_ONE_PAGE = 30;
  const TOTOAL_PAGES = Math.ceil(data.length / NUMBER_OF_FEED_IN_ONE_PAGE);

  const pages = new Array(TOTOAL_PAGES).fill(0).map((_, index) => index + 1);

  return {
    pages: pages,
    index: 1,
  };
}

export function getCurrentPageImageData(data, index) {
  const NUMBER_OF_FEED_IN_ONE_PAGE = 30;
  const startIndex = (index - 1) * NUMBER_OF_FEED_IN_ONE_PAGE;
  const endIndex = index * NUMBER_OF_FEED_IN_ONE_PAGE;
  const currentPageData = data
    .slice(startIndex, endIndex)
    .map((e) => `https://drive.google.com/uc?export=view&id=${e}`);

  return currentPageData;
}

export default images;
