import React from "react";

export default function Placeholder({ className }) {
  return <span className={`placeholder ${className}`}></span>;
}

const PlaceholderTitle = ({ col = 6 }) => (
  <h5 className="card-title placeholder-glow">
    <span className={`placeholder col-${col}`}></span>
  </h5>
);

const PlaceholderImage = ({ height = 469, className }) => (
  <div
    className={"bg-secondary " + className}
    style={{ height: `${height}px` }}
  ></div>
);

const PlaceholderParagraph = () => (
  <p className="card-text placeholder-glow">
    <span className="placeholder me-1 col-7"></span>
    <span className="placeholder col-4"></span>
    <span className="placeholder me-1 col-4"></span>
    <span className="placeholder col-6"></span>
    <span className="placeholder me-1 col-8"></span>
    <span className="placeholder me-1 col-6"></span>
    <span className="placeholder col-3"></span>
  </p>
);

Placeholder.Title = PlaceholderTitle;
Placeholder.Paragraph = PlaceholderParagraph;
Placeholder.Image = PlaceholderImage;
