import React from "react";
import usePagination from "~/utils/hooks/usePagination";

export default function Pagination({ data, setIndex, currentIndex }) {
  const clickHandler = React.useCallback((e) => {
    setIndex(Number(e.target.value));
  }, []);

  const renderItem = React.useCallback(
    (item, index) => (
      <Btn
        key={index}
        active={currentIndex === item}
        value={item}
        onClick={clickHandler}
      />
    ),
    [currentIndex]
  );

  return (
    <div className="p-2 d-flex align-items-center flex-wrap">
      {data.map(renderItem)}
    </div>
  );
}

const Btn = React.memo(({ active, onClick, value }) => (
  <button
    type="button"
    onClick={onClick}
    value={value}
    className={`btn ${
      active ? "btn-primary" : "btn-outline-primary"
    } me-2 mb-2`}
  >
    {value}
  </button>
));
