import React from "react";
import Pagination from "~/common/components/major/Pagination";
import images, {
  getCurrentPageImageData,
  getInitialImageData,
} from "~/utils/api/images";
import { View } from "react-native";
import ImageFeed from "~/common/components/major/ImageFeed";

export default function Images() {
  const [state, setState] = React.useState({ index: 1, pages: [] });

  React.useEffect(() => {
    const initialData = getInitialImageData(images);
    setState(initialData);
  }, []);

  const setIndex = React.useCallback((id) => {
    setState((prev) => ({ ...prev, index: id }));
  }, []);

  const modifyData = React.useMemo(
    () => getCurrentPageImageData(images, state.index),
    [state.index]
  );

  return (
    <View style={{ flex: 1 }}>
      <ImageFeed
        currentRoute={"Image"}
        currentIndex={state.index}
        data={modifyData}
        ListHeaderComponent={
          <Pagination
            data={state.pages}
            setIndex={setIndex}
            currentIndex={state.index}
          />
        }
      />
    </View>
  );
}
